struct stat_double {
    double numbers[5];
    double mystery;
};

void who_am_i(stat_double &data) {
    data.mystery = data.numbers[0];
    for (int i = 1; i < 5; i++) {
        if (data.numbers[i] > data.mystery) {
            data.mystery = data.numbers[i];
        }
    }
}

int main() {
    stat_double d;
    d.numbers[0] = 10.0;
    d.numbers[1] = 2.5;
    d.numbers[2] = 15.3;
    d.numbers[3] = 8.0;
    d.numbers[4] = 12.1;
    who_am_i(d);
    return 0;
}
